// Si no tienes la función RPC, usamos la query directa vía REST
// Nota: Este nodo procesa la respuesta de Supabase
const data = $input.first().json;

// Manejar array de resultados o un objeto con total
let totalLeads = 0;
let byAgent = {};
let bySource = {};

if (Array.isArray(data)) {
  totalLeads = data.length;
  for (const lead of data) {
    const agent = lead.assigned_agent || lead.asesor || 'Sin asignar';
    byAgent[agent] = (byAgent[agent] || 0) + 1;
    const source = lead.source || lead.fuente || 'Directo';
    bySource[source] = (bySource[source] || 0) + 1;
  }
} else {
  // Si es un objeto con totales pre-calculados
  totalLeads = data.total_leads || data.count || 0;
  byAgent = data.by_agent || {};
  bySource = data.by_source || {};
}

// Construir líneas por asesor
const agentLines = Object.entries(byAgent)
  .sort((a, b) => b[1] - a[1])
  .map(([name, count]) => `   • ${name}: ${count} lead${count !== 1 ? 's' : ''}`)
  .join('\n');

// Construir líneas por fuente
const sourceLines = Object.entries(bySource)
  .sort((a, b) => b[1] - a[1])
  .map(([src, count]) => `   • ${src}: ${count}`)
  .join('\n');

const today = new Date().toLocaleDateString('es-CO', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric',
  timeZone: 'America/Bogota'
});

const emoji = totalLeads >= 10 ? '🔥' : totalLeads >= 5 ? '✅' : totalLeads > 0 ? '📋' : '😴';

const message = [
  `${emoji} *REPORTE DIARIO - GO EASY CRM*`,
  `📅 ${today}`,
  '',
  `📊 *Total leads hoy: ${totalLeads}*`,
  '',
  agentLines ? `🧑‍💼 *Por asesor:*\n${agentLines}` : null,
  sourceLines ? `\n🔗 *Por fuente:*\n${sourceLines}` : null,
  '',
  '_Reporte automático - Go Easy CRM_ 🤖',
].filter(Boolean).join('\n');

return [{ json: { message, totalLeads } }];
